 58→class ReviewerViewModel(cardMediaPlayer: CardMediaPlayer) :
 59→    CardViewerViewModel(cardMediaPlayer),
 60→    ChangeManager.Subscriber {
 61→
 62→    private var queueState: Deferred<CurrentQueueState?> = asyncIO {
 63→        // this assumes that the Reviewer won't be launched if there isn't a queueState
 64→        withCol { sched.currentQueueState() }!!
 65→    }
 66→    override var currentCard = asyncIO {
 67→        queueState.await()!!.topCard
 68→    }
 69→    var isQueueFinishedFlow = MutableSharedFlow<Boolean>()
 70→    val isMarkedFlow = MutableStateFlow(false)
 71→    val flagCodeFlow = MutableStateFlow(Flag.NONE.code)
 72→    val actionFeedbackFlow = MutableSharedFlow<String>()
 73→    val canBuryNoteFlow = MutableStateFlow(true)
 74→    val canSuspendNoteFlow = MutableStateFlow(true)
 75→    val undoLabelFlow = MutableStateFlow<String?>(null)
 76→    val redoLabelFlow = MutableStateFlow<String?>(null)
 77→    val countsFlow = MutableStateFlow(Counts() to Counts.Queue.NEW)
 78→
 79→    override val server = AnkiServer(this).also { it.start() }
 80→    private val stateMutationKey = TimeManager.time.intTimeMS().toString()
 81→    val statesMutationEval = MutableSharedFlow<String>()
 82→
 83→    private val autoAdvance = AutoAdvance(this)
 84→
 85→    /**
 86→     * A flag that determines if the SchedulingStates in CurrentQueueState are
 87→     * safe to persist in the database when answering a card. This is used to
 88→     * ensure that the custom JS scheduler has persisted its SchedulingStates
 89→     * back to the Reviewer before we save it to the database. If the custom
 90→     * scheduler has not been configured, then it is safe to immediately set
 91→     * this to true.
 92→     *
 93→     * This flag should be set to false when we show the front of the card
 94→     * and only set to true once we know the custom scheduler has finished its
 95→     * execution, or set to true immediately if the custom scheduler has not
 96→     * been configured.
 97→     */
 98→    private var statesMutated = true
 99→
100→    val answerButtonsNextTimeFlow: MutableStateFlow<AnswerButtonsNextTime?> = MutableStateFlow(null)
101→    private val shouldShowNextTimes: Deferred<Boolean> = asyncIO {
102→        withCol { config.get("estTimes") ?: true }
103→    }
104→
105→    init {
106→        ChangeManager.subscribe(this)
107→        launchCatchingIO {
108→            updateUndoAndRedoLabels()
109→        }
110→        cardMediaPlayer.setOnSoundGroupCompletedListener {
111→            launchCatchingIO {
112→                if (!autoAdvance.shouldWaitForAudio()) return@launchCatchingIO
113→
114→                if (showingAnswer.value) {
115→                    autoAdvance.onShowAnswer()
116→                } else {
117→                    autoAdvance.onShowQuestion()
118→                }
119→            }
120→        }
121→    }
122→
123→    /* *********************************************************************************************
124→    ************************ Public methods: meant to be used by the View **************************
125→    ********************************************************************************************* */
126→
127→    override fun onPageFinished(isAfterRecreation: Boolean) {
128→        if (isAfterRecreation) {
129→            launchCatchingIO {
130→                // TODO handle "Don't keep activities"
131→                if (showingAnswer.value) showAnswerInternal() else showQuestion()
132→            }
133→        } else {
134→            launchCatchingIO {
135→                updateCurrentCard()
136→            }
137→        }
138→    }
139→
140→    fun showAnswer() {
141→        launchCatchingIO {
142→            while (!statesMutated) {
143→                delay(50)
144→            }
145→            updateNextTimes()
146→            showAnswerInternal()
147→            loadAndPlaySounds(CardSide.ANSWER)
148→            if (!autoAdvance.shouldWaitForAudio()) {
149→                autoAdvance.onShowAnswer()
150→            } // else wait for onSoundGroupCompleted
151→        }
152→    }
153→
154→    fun answerAgain() = answerCard(Ease.AGAIN)
155→    fun answerHard() = answerCard(Ease.HARD)
156→    fun answerGood() = answerCard(Ease.GOOD)
157→    fun answerEasy() = answerCard(Ease.EASY)
158→
159→    fun toggleMark() {
160→        launchCatchingIO {
161→            val card = currentCard.await()
162→            val note = withCol { card.note(this@withCol) }
163→            NoteService.toggleMark(note)
164→            isMarkedFlow.emit(NoteService.isMarked(note))
165→        }
166→    }
167→
168→    fun setFlag(flag: Flag) {
169→        launchCatchingIO {
170→            val card = currentCard.await()
171→            undoableOp {
172→                setUserFlagForCards(listOf(card.id), flag.code)
173→            }
174→            flagCodeFlow.emit(flag.code)
175→        }
176→    }
177→
178→    fun onStateMutationCallback() {
179→        statesMutated = true
180→    }
181→
182→    suspend fun getEditNoteDestination(): NoteEditorLauncher {
183→        return NoteEditorLauncher.EditNoteFromPreviewer(currentCard.await().id)
184→    }
185→
186→    fun refreshCard() {
187→        launchCatchingIO {
188→            updateCurrentCard()
189→        }
190→    }
191→
192→    suspend fun getCardInfoDestination(): CardInfoDestination {
193→        return CardInfoDestination(currentCard.await().id)
194→    }
195→
196→    suspend fun getDeckOptionsDestination(): DeckOptionsDestination {
197→        val deckId = withCol { decks.getCurrentId() }
198→        val isFiltered = withCol { decks.isFiltered(deckId) }
199→        return DeckOptionsDestination(deckId, isFiltered)
200→    }
201→
202→    fun deleteNote() {
203→        launchCatchingIO {
204→            val cardId = currentCard.await().id
205→            val noteCount = undoableOp {
206→                removeNotes(cids = listOf(cardId))
207→            }.count
208→            actionFeedbackFlow.emit(CollectionManager.TR.browsingCardsDeleted(noteCount))
209→            updateCurrentCard()
210→        }
211→    }
212→
213→    fun buryCard() {
214→        launchCatchingIO {
215→            val cardId = currentCard.await().id
216→            val noteCount = undoableOp {
217→                sched.buryCards(cids = listOf(cardId))
218→            }.count
219→            actionFeedbackFlow.emit(CollectionManager.TR.studyingCardsBuried(noteCount))
220→            updateCurrentCard()
221→        }
222→    }
223→
224→    fun buryNote() {
225→        launchCatchingIO {
226→            val noteId = currentCard.await().nid
227→            val noteCount = undoableOp {
228→                sched.buryNotes(nids = listOf(noteId))
229→            }.count
230→            actionFeedbackFlow.emit(CollectionManager.TR.studyingCardsBuried(noteCount))
231→            updateCurrentCard()
232→        }
233→    }
234→
235→    fun suspendCard() {
236→        launchCatchingIO {
237→            val cardId = currentCard.await().id
238→            undoableOp {
239→                sched.suspendCards(ids = listOf(cardId))
240→            }.count
241→            actionFeedbackFlow.emit(CollectionManager.TR.studyingCardSuspended())
242→            updateCurrentCard()
243→        }
244→    }
245→
246→    fun suspendNote() {
247→        launchCatchingIO {
248→            val noteId = currentCard.await().nid
249→            undoableOp {
250→                sched.suspendNotes(ids = listOf(noteId))
251→            }
252→            actionFeedbackFlow.emit(CollectionManager.TR.studyingNoteSuspended())
253→            updateCurrentCard()
254→        }
255→    }
256→
257→    fun undo() {
258→        launchCatchingIO {
259→            val changes = undoableOp {
260→                undo()
261→            }
262→            val message = if (changes.operation.isEmpty()) {
263→                CollectionManager.TR.actionsNothingToUndo()
264→            } else {
265→                CollectionManager.TR.undoActionUndone(changes.operation)
266→            }
267→            actionFeedbackFlow.emit(message)
268→            updateCurrentCard()
269→        }
270→    }
271→
272→    fun redo() {
273→        launchCatchingIO {
274→            val changes = undoableOp {
275→                redo()
276→            }
277→            val message = if (changes.operation.isEmpty()) {
278→                CollectionManager.TR.actionsNothingToRedo()
279→            } else {
280→                CollectionManager.TR.undoRedoAction(changes.operation)
281→            }
282→            actionFeedbackFlow.emit(message)
283→            updateCurrentCard()
284→        }
285→    }
286→
287→    fun userAction(@Reviewer.UserAction number: Int) {
288→        launchCatchingIO {
289→            eval.emit("javascript: ankidroid.userAction($number);")
290→        }
291→    }
292→
293→    fun stopAutoAdvance() {
294→        autoAdvance.cancelQuestionAndAnswerActionJobs()
295→    }
296→
297→    /* *********************************************************************************************
298→    *************************************** Internal methods ***************************************
299→    ********************************************************************************************* */
300→
301→    override suspend fun handlePostRequest(uri: String, bytes: ByteArray): ByteArray {
302→        return if (uri.startsWith(AnkiServer.ANKI_PREFIX)) {
303→            when (uri.substring(AnkiServer.ANKI_PREFIX.length)) {
304→                "getSchedulingStatesWithContext" -> getSchedulingStatesWithContext()
305→                "setSchedulingStates" -> setSchedulingStates(bytes)
306→                else -> super.handlePostRequest(uri, bytes)
307→            }
308→        } else {
309→            super.handlePostRequest(uri, bytes)
310→        }
311→    }
312→
313→    override suspend fun showQuestion() {
314→        super.showQuestion()
315→        runStateMutationHook()
316→        if (!autoAdvance.shouldWaitForAudio()) {
317→            autoAdvance.onShowQuestion()
318→        } // else run in onSoundGroupCompleted
319→    }
320→
321→    private suspend fun runStateMutationHook() {
322→        val state = queueState.await() ?: return
323→        val js = state.customSchedulingJs
324→        if (js.isEmpty()) {
325→            statesMutated = true
326→            return
327→        }
328→        statesMutated = false
329→        statesMutationEval.emit(
330→            "anki.mutateNextCardStates('$stateMutationKey', async (states, customData, ctx) => { $js });"
331→        )
332→    }
333→
334→    private suspend fun getSchedulingStatesWithContext(): ByteArray {
335→        val state = queueState.await() ?: return ByteArray(0)
336→        return state.schedulingStatesWithContext().toBuilder()
337→            .mergeStates(
338→                state.states.toBuilder().mergeCurrent(
339→                    state.states.current.toBuilder()
340→                        .setCustomData(state.topCard.toBackendCard().customData).build()
341→                ).build()
342→            )
343→            .build()
344→            .toByteArray()
345→    }
346→
347→    private suspend fun setSchedulingStates(bytes: ByteArray): ByteArray {
348→        val state = queueState.await() ?: return ByteArray(0)
349→        val req = SetSchedulingStatesRequest.parseFrom(bytes)
350→        if (req.key == stateMutationKey) {
351→            state.states = req.states
352→        }
353→        return ByteArray(0)
354→    }
355→
356→    private fun answerCard(ease: Ease) {
357→        launchCatchingIO {
358→            queueState.await()?.let {
359→                undoableOp { sched.answerCard(it, ease.value) }
360→                updateCurrentCard()
361→            }
362→        }
363→    }
364→
365→    private suspend fun loadAndPlaySounds(side: CardSide) {
366→        cardMediaPlayer.loadCardSounds(currentCard.await())
367→        cardMediaPlayer.playAllSoundsForSide(side)
368→    }
369→
370→    private suspend fun updateMarkedStatus() {
371→        val card = currentCard.await()
372→        val isMarkedValue = withCol { card.note(this@withCol).hasTag(this@withCol, MARKED_TAG) }
373→        isMarkedFlow.emit(isMarkedValue)
374→    }
375→
376→    private suspend fun updateCurrentCard() {
377→        queueState = asyncIO {
378→            withCol {
379→                sched.currentQueueState()
380→            }
381→        }
382→        val state = queueState.await()
383→        if (state == null) {
384→            isQueueFinishedFlow.emit(true)
385→            return
386→        }
387→
388→        val card = state.topCard
389→        currentCard = CompletableDeferred(card)
390→        autoAdvance.onCardChange(card)
391→        showQuestion()
392→        loadAndPlaySounds(CardSide.QUESTION)
393→        updateMarkedStatus()
394→        flagCodeFlow.emit(card.userFlag())
395→        canBuryNoteFlow.emit(isBuryNoteAvailable(card))
396→        canSuspendNoteFlow.emit(isSuspendNoteAvailable(card))
397→        countsFlow.emit(state.counts to state.countsIndex)
398→    }
399→
400→    // TODO
401→    override suspend fun typeAnsFilter(text: String): String {
402→        return text
403→    }
404→
405→    private suspend fun updateUndoAndRedoLabels() {
406→        undoLabelFlow.emit(withCol { undoLabel() })
407→        redoLabelFlow.emit(withCol { redoLabel() })
408→    }
409→
410→    private suspend fun updateNextTimes() {
411→        if (!shouldShowNextTimes.await()) return
412→        val state = queueState.await() ?: return
413→
414→        val nextTimes = AnswerButtonsNextTime.from(state)
415→        answerButtonsNextTimeFlow.emit(nextTimes)
416→    }
417→
418→    override fun opExecuted(changes: OpChanges, handler: Any?) {
419→        launchCatchingIO { updateUndoAndRedoLabels() }
420→    }
421→
422→    companion object {
423→        fun factory(soundPlayer: CardMediaPlayer): ViewModelProvider.Factory {
424→            return viewModelFactory {
425→                initializer {
426→                    ReviewerViewModel(soundPlayer)
427→                }
428→            }
429→        }
430→
431→        fun buildAnswerButtonText(title: String, nextTime: String?): CharSequence {
432→            return if (nextTime != null) {
433→                buildSpannedString {
434→                    inSpans(RelativeSizeSpan(0.8F)) {
435→                        append(nextTime)
436→                    }
437→                    append("\n")
438→                    append(title)
439→                }
440→            } else {
441→                title
442→            }
443→        }
444→    }
445→}
