 63→class ReviewerFragment :
 64→    CardViewerFragment(R.layout.reviewer2),
 65→    BaseSnackbarBuilderProvider,
 66→    Toolbar.OnMenuItemClickListener {
 67→
 68→    override val viewModel: ReviewerViewModel by viewModels {
 69→        ReviewerViewModel.factory(CardMediaPlayer())
 70→    }
 71→
 72→    override val webView: WebView
 73→        get() = requireView().findViewById(R.id.webview)
 74→
 75→    override val baseSnackbarBuilder: SnackbarBuilder = {
 76→        anchorView = this@ReviewerFragment.view?.findViewById(R.id.buttons_area)
 77→    }
 78→
 79→    override fun onStop() {
 80→        super.onStop()
 81→        if (!requireActivity().isChangingConfigurations) {
 82→            viewModel.stopAutoAdvance()
 83→        }
 84→    }
 85→
 86→    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
 87→        super.onViewCreated(view, savedInstanceState)
 88→
 89→        setupImmersiveMode(view)
 90→        setupAnswerButtons(view)
 91→        setupCounts(view)
 92→
 93→        view.findViewById<MaterialToolbar>(R.id.toolbar).apply {
 94→            setOnMenuItemClickListener(this@ReviewerFragment)
 95→            setNavigationOnClickListener { requireActivity().onBackPressedDispatcher.onBackPressed() }
 96→            (menu as? MenuBuilder)?.let {
 97→                setupMenuItems(it)
 98→                it.setOptionalIconsVisible(true)
 99→                requireContext().increaseHorizontalPaddingOfOverflowMenuIcons(it)
100→            }
101→        }
102→
103→        viewModel.actionFeedbackFlow.flowWithLifecycle(lifecycle)
104→            .collectIn(lifecycleScope) { message ->
105→                showSnackbar(message, duration = 500)
106→            }
107→
108→        viewModel.isQueueFinishedFlow.collectIn(lifecycleScope) { isQueueFinished ->
109→            if (isQueueFinished) {
110→                requireActivity().run {
111→                    setResult(RESULT_NO_MORE_CARDS)
112→                    finish()
113→                }
114→            }
115→        }
116→
117→        viewModel.statesMutationEval.collectIn(lifecycleScope) { eval ->
118→            webView.evaluateJavascript(eval) {
119→                viewModel.onStateMutationCallback()
120→            }
121→        }
122→    }
123→
