160→    private fun setupAnswerButtons(view: View) {
161→        val hideAnswerButtons = sharedPrefs().getBoolean(getString(R.string.hide_answer_buttons_key), false)
162→        if (hideAnswerButtons) {
163→            view.findViewById<FrameLayout>(R.id.buttons_area).isVisible = false
164→            return
165→        }
166→
167→        fun MaterialButton.setAnswerButtonNextTime(@StringRes title: Int, nextTime: String?) {
168→            val titleString = context.getString(title)
169→            text = ReviewerViewModel.buildAnswerButtonText(titleString, nextTime)
170→        }
171→
172→        val againButton = view.findViewById<MaterialButton>(R.id.again_button).apply {
173→            setOnClickListener { viewModel.answerAgain() }
174→        }
175→        val hardButton = view.findViewById<MaterialButton>(R.id.hard_button).apply {
