300→
301→    override suspend fun handlePostRequest(uri: String, bytes: ByteArray): ByteArray {
302→        return if (uri.startsWith(AnkiServer.ANKI_PREFIX)) {
303→            when (uri.substring(AnkiServer.ANKI_PREFIX.length)) {
304→                "getSchedulingStatesWithContext" -> getSchedulingStatesWithContext()
305→                "setSchedulingStates" -> setSchedulingStates(bytes)
306→                else -> super.handlePostRequest(uri, bytes)
307→            }
308→        } else {
309→            super.handlePostRequest(uri, bytes)
310→        }
311→    }
312→
313→    override suspend fun showQuestion() {
314→        super.showQuestion()
315→        runStateMutationHook()
316→        if (!autoAdvance.shouldWaitForAudio()) {
317→            autoAdvance.onShowQuestion()
318→        } // else run in onSoundGroupCompleted
319→    }
320→
321→    private suspend fun runStateMutationHook() {
322→        val state = queueState.await() ?: return
323→        val js = state.customSchedulingJs
324→        if (js.isEmpty()) {
325→            statesMutated = true
326→            return
327→        }
328→        statesMutated = false
329→        statesMutationEval.emit(
330→            "anki.mutateNextCardStates('$stateMutationKey', async (states, customData, ctx) => { $js });"
331→        )
332→    }
333→
334→    private suspend fun getSchedulingStatesWithContext(): ByteArray {
335→        val state = queueState.await() ?: return ByteArray(0)
336→        return state.schedulingStatesWithContext().toBuilder()
337→            .mergeStates(
338→                state.states.toBuilder().mergeCurrent(
339→                    state.states.current.toBuilder()
340→                        .setCustomData(state.topCard.toBackendCard().customData).build()
341→                ).build()
342→            )
343→            .build()
344→            .toByteArray()
345→    }
346→
347→    private suspend fun setSchedulingStates(bytes: ByteArray): ByteArray {
348→        val state = queueState.await() ?: return ByteArray(0)
349→        val req = SetSchedulingStatesRequest.parseFrom(bytes)
350→        if (req.key == stateMutationKey) {
351→            state.states = req.states
352→        }
353→        return ByteArray(0)
354→    }
355→
356→    private fun answerCard(ease: Ease) {
357→        launchCatchingIO {
358→            queueState.await()?.let {
359→                undoableOp { sched.answerCard(it, ease.value) }
360→                updateCurrentCard()
361→            }
362→        }
363→    }
364→
365→    private suspend fun loadAndPlaySounds(side: CardSide) {
366→        cardMediaPlayer.loadCardSounds(currentCard.await())
367→        cardMediaPlayer.playAllSoundsForSide(side)
368→    }
369→
370→    private suspend fun updateMarkedStatus() {
371→        val card = currentCard.await()
372→        val isMarkedValue = withCol { card.note(this@withCol).hasTag(this@withCol, MARKED_TAG) }
373→        isMarkedFlow.emit(isMarkedValue)
374→    }
375→
376→    private suspend fun updateCurrentCard() {
377→        queueState = asyncIO {
378→            withCol {
379→                sched.currentQueueState()
380→            }
381→        }
382→        val state = queueState.await()
383→        if (state == null) {
384→            isQueueFinishedFlow.emit(true)
385→            return
386→        }
387→
388→        val card = state.topCard
389→        currentCard = CompletableDeferred(card)
390→        autoAdvance.onCardChange(card)
391→        showQuestion()
392→        loadAndPlaySounds(CardSide.QUESTION)
393→        updateMarkedStatus()
394→        flagCodeFlow.emit(card.userFlag())
395→        canBuryNoteFlow.emit(isBuryNoteAvailable(card))
396→        canSuspendNoteFlow.emit(isSuspendNoteAvailable(card))
397→        countsFlow.emit(state.counts to state.countsIndex)
398→    }
