410→    private suspend fun updateNextTimes() {
411→        if (!shouldShowNextTimes.await()) return
412→        val state = queueState.await() ?: return
413→
414→        val nextTimes = AnswerButtonsNextTime.from(state)
415→        answerButtonsNextTimeFlow.emit(nextTimes)
416→    }
