311→    private fun setupImmersiveMode(view: View) {
312→        val hideSystemBarsSetting = HideSystemBars.from(requireContext())
313→        val barsToHide = when (hideSystemBarsSetting) {
314→            HideSystemBars.NONE -> return
315→            HideSystemBars.STATUS_BAR -> WindowInsetsCompat.Type.statusBars()
316→            HideSystemBars.NAVIGATION_BAR -> WindowInsetsCompat.Type.navigationBars()
317→            HideSystemBars.ALL -> WindowInsetsCompat.Type.systemBars()
318→        }
319→
320→        val window = requireActivity().window
321→        with(WindowInsetsControllerCompat(window, window.decorView)) {
322→            hide(barsToHide)
323→            systemBarsBehavior = WindowInsetsControllerCompat.BEHAVIOR_SHOW_TRANSIENT_BARS_BY_SWIPE
324→        }
325→
326→        val ignoreDisplayCutout = sharedPrefs().getBoolean(getString(R.string.ignore_display_cutout_key), false)
327→        ViewCompat.setOnApplyWindowInsetsListener(view) { v, insets ->
328→            val typeMask = if (ignoreDisplayCutout) {
329→                WindowInsetsCompat.Type.systemBars()
330→            } else {
331→                WindowInsetsCompat.Type.systemBars() or WindowInsetsCompat.Type.displayCutout()
332→            }
333→            val bars = insets.getInsets(typeMask)
334→            v.updatePadding(
335→                left = bars.left,
336→                top = bars.top,
337→                right = bars.right,
338→                bottom = bars.bottom
339→            )
340→            WindowInsetsCompat.CONSUMED
341→        }
342→    }
