182→        @CheckResult
183→        fun fromPreferenceString(string: String?): MutableList<MappableBinding> {
184→            if (string.isNullOrEmpty()) return ArrayList()
185→            try {
186→                val version = string.takeWhile { x -> x != '/' }
187→                val remainder = string.substring(version.length + 1) // skip the /
188→                if (version != "1") {
189→                    Timber.w("cannot handle version '$version'")
190→                    return ArrayList()
191→                }
192→                return remainder.split(PREF_SEPARATOR).mapNotNull { fromString(it) }.toMutableList()
193→            } catch (e: Exception) {
194→                Timber.w(e, "Failed to deserialize preference")
195→                return ArrayList()
196→            }
197→        }
